//! `baton-do mkdir` logic: create a collection at the path
//! specified by the input target.
//!
//! Wraps the existing `RodsConnection::create_collection` (which
//! itself wraps `shim_create_coll` over `rcCollCreate`). The
//! `recurse` flag maps to upstream baton-do's `arguments.recurse`
//! and gives `mkdir -p` semantics: intermediate parents that
//! don't exist are created in the same call. Without it, iRODS
//! errors when the parent is missing.
//!
//! Data-object targets are an error — mkdir is a collection-only
//! operation. Mirrors upstream baton-do's `JSON_MKDIR_OP` which
//! uses `JSON_COLLECTION_KEY` / `Target::Collection` exclusively.

use crate::connection::RodsConnection;
use crate::error::BatonError;
use crate::types::Target;

/// Caller-controlled flags for [`mkdir_one`].
#[derive(Debug, Default, Clone, Copy)]
pub struct MkdirOptions {
    /// `mkdir -p` semantics — create intermediate parents that
    /// don't exist. Maps to `RECURSIVE_OPR__KW` server-side.
    /// Without it, iRODS errors when the parent path is missing.
    pub recurse: bool,
}

/// Create the collection at `target.collection`. Echoes the input
/// target unchanged on success — no new fields populated, since
/// the operation is purely a side-effect.
///
/// Data-object inputs are an error before any iRODS call.
pub fn mkdir_one(
    conn: &mut RodsConnection,
    target: Target,
    opts: &MkdirOptions,
) -> Result<Target, BatonError> {
    let path = match &target {
        Target::Collection(c) => c.collection.clone(),
        Target::DataObject(d) => {
            // -310000 USER_FILE_DOES_NOT_EXIST. Upstream baton
            // surfaces the iRODS code on a wrong-type target;
            // downstream consumers (partisan, extendo) regex on
            // the iRODS code, not on baton-rs's synthetic -1.
            // Audit cleanup landed in #83.
            return Err(BatonError::from_irods_with_context(
                -310000,
                &format!(
                    "baton-do mkdir: target is a data object, not a collection: {}/{}",
                    d.collection, d.data_object
                ),
            ));
        }
    };
    // Wrap iRODS errors with operation context so partisan's
    // `pytest.raises(RodsError, match="create collection")` matches
    // (e.g. `test_create_collection_parents`,
    // `test_create_collection_existing`). Preserves the iRODS code
    // and the original symbolic-name + descriptive-phrase prose
    // from `BatonError::from_irods`. See #57 (Cluster A).
    conn.create_collection(&path, opts.recurse).map_err(|e| BatonError {
        code: e.code,
        message: format!("create collection {}: {}", path, e.message),
    })?;
    Ok(target)
}

/// Same as [`mkdir_one`], but catches iRODS errors and emits the
/// input annotated with an `"error"` field instead of
/// propagating. Mirrors the rest of the operations layer's
/// `*_one_annotated` wrappers.
pub fn mkdir_one_annotated(
    conn: &mut RodsConnection,
    target: Target,
    opts: &MkdirOptions,
) -> Target {
    super::annotate_failure(target, |t| mkdir_one(conn, t, opts))
}
